// ============================================================
// pages/MerchantDashboard.jsx — Merchant Home Page
// ============================================================
// Shows:
//  - Welcome message with business name
//  - Current application status (if submitted)
//  - Quick action buttons: Apply, Upload Docs, Check Status
// ============================================================

import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { applicationAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/dashboard.css";

function MerchantDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [appStatus, setAppStatus] = useState(null);   // null = not submitted
  const [loading,   setLoading]   = useState(true);

  // On mount: check if application exists
  useEffect(() => {
    applicationAPI.getStatus()
      .then((res) => setAppStatus(res.data.status))
      .catch(() => setAppStatus(null))  // 404 means not submitted yet
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="dashboard-layout">
      {/* ---- Sidebar ---- */}
      <aside className="sidebar">
        <div className="sidebar-logo">PayOnboard</div>
        <ul className="sidebar-nav">
          <li><Link to="/dashboard" className="active">🏠 Dashboard</Link></li>
          <li><Link to="/apply">📄 Apply Now</Link></li>
          <li><Link to="/status">🔍 Track Status</Link></li>
        </ul>
        <div className="sidebar-footer">
          <button
            onClick={logout}
            style={{ background: "none", border: "none", color: "var(--color-text-secondary)", cursor: "pointer", fontSize: "0.875rem" }}
          >
            🚪 Logout
          </button>
        </div>
      </aside>

      {/* ---- Main Content ---- */}
      <main className="main-content">
        <div className="topbar">
          <div>
            <h1 className="page-title">Dashboard</h1>
            <p className="page-subtitle">Welcome, {user?.email}</p>
          </div>
        </div>

        {/* Status Summary Card */}
        <div className="card" style={{ marginBottom: "var(--space-xl)" }}>
          <h2 style={{ marginBottom: "var(--space-md)", fontSize: "1.125rem", fontWeight: 600 }}>
            Application Status
          </h2>
          {loading ? (
            <div className="spinner" />
          ) : appStatus ? (
            <div style={{ display: "flex", alignItems: "center", gap: "var(--space-md)" }}>
              <span className={`badge badge-${appStatus}`}>{appStatus.replace("_", " ")}</span>
              <Link to="/status">View full details →</Link>
            </div>
          ) : (
            <div>
              <p style={{ color: "var(--color-text-secondary)", marginBottom: "var(--space-md)" }}>
                You haven't submitted an application yet.
              </p>
              <button className="btn btn-primary" onClick={() => navigate("/apply")}>
                Start Application
              </button>
            </div>
          )}
        </div>

        {/* Quick Actions Grid */}
        <h2 style={{ marginBottom: "var(--space-md)", fontWeight: 600 }}>Quick Actions</h2>
        <div className="stats-grid">
          <div className="stat-card" style={{ cursor: "pointer" }} onClick={() => navigate("/apply")}>
            <div style={{ fontSize: "2rem" }}>📝</div>
            <div className="stat-label" style={{ marginTop: "var(--space-sm)" }}>Submit Application</div>
            <div style={{ fontSize: "0.8125rem", color: "var(--color-text-secondary)", marginTop: "4px" }}>
              Fill & submit onboarding form
            </div>
          </div>
          <div className="stat-card" style={{ cursor: "pointer" }} onClick={() => navigate("/apply#documents")}>
            <div style={{ fontSize: "2rem" }}>📁</div>
            <div className="stat-label" style={{ marginTop: "var(--space-sm)" }}>Upload Documents</div>
            <div style={{ fontSize: "0.8125rem", color: "var(--color-text-secondary)", marginTop: "4px" }}>
              PAN, GST, Bank Statement, etc.
            </div>
          </div>
          <div className="stat-card" style={{ cursor: "pointer" }} onClick={() => navigate("/status")}>
            <div style={{ fontSize: "2rem" }}>🔍</div>
            <div className="stat-label" style={{ marginTop: "var(--space-sm)" }}>Track Status</div>
            <div style={{ fontSize: "0.8125rem", color: "var(--color-text-secondary)", marginTop: "4px" }}>
              Check approval status & remarks
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

export default MerchantDashboard;
